SELECT drone_model 
FROM drones 
ORDER BY max_flight_time ASC;

SELECT drone_model, max_flight_time, weight
FROM drones
WHERE drone_id = 1;

SELECT COUNT(DISTINCT f.drone_id) AS total_drones
FROM flights f
WHERE f.location LIKE '%California%' AND f.flight_purpose = 'surveillance';

SELECT COUNT(DISTINCT flight_purpose) 
FROM flights 
WHERE pilot_id = (SELECT pilot_id FROM pilots WHERE pilot_name = 'John Doe');
